1	import { api } from './client';
2	
3	/**
4	 * Connections API — the six configurable connection types (CLAUDE.md §4).
5	 * ADF + Airflow are orchestration providers, not datasources, but they are
6	 * still `connections` rows and managed through the same CRUD surface.
7	 */
8	
9	export const CONNECTION_TYPES = [
10	  'snowflake',
11	  'adls_gen2',
12	  's3',
13	  'unity_catalog',
14	  'adf',
15	  'airflow',
16	] as const;
17	export type ConnectionType = (typeof CONNECTION_TYPES)[number];
18	
19	/**
20	 * Datasource vs orchestration is the load-bearing distinction in DataQ
21	 * (CLAUDE.md §4): datasources are stores you write checks against; ADF/Airflow
22	 * are orchestration providers we monitor + trigger from, never queryable. This
23	 * map is the single source for that split — the add-connection picker and the
24	 * sectioned list both derive their groups from it (no hardcoded lists elsewhere).
25	 */
26	export const CONNECTION_KINDS = ['datasource', 'orchestration'] as const;
27	export type ConnectionKind = (typeof CONNECTION_KINDS)[number];
28	
29	export const CONNECTION_KIND: Record<ConnectionType, ConnectionKind> = {
30	  snowflake: 'datasource',
31	  adls_gen2: 'datasource',
