1	import type { ConnectionType } from '../../api/connections';
2	import { type RunTarget, targetString } from '../../api/suites';
3	
4	/**
5	 * A suite's run target (#215) is datasource-shaped: SQL warehouses identify a
6	 * `table` (+ optional `schema`), Unity Catalog adds a required `catalog`, and
7	 * flat-file stores (ADLS / S3) identify a `path` (+ optional `file_format`).
8	 * `targetKind` collapses the six datasource types to the three input shapes the
9	 * editor renders; orchestration types never reach here (they can't back a suite).
10	 */
11	export type TargetKind = 'sql' | 'uc' | 'flatfile';
12	
13	export function targetKind(type: ConnectionType): TargetKind | null {
14	  switch (type) {
15	    case 'snowflake':
16	      return 'sql';
17	    case 'unity_catalog':
18	      return 'uc';
19	    case 'adls_gen2':
20	    case 's3':
21	      return 'flatfile';
22	    default:
23	      return null; // adf / airflow — not a datasource
24	  }
25	}
26	
27	/**
28	 * Collapse a stored run target to a one-line summary for read-only display:
29	 * flat files show their `path`; SQL / Unity Catalog show the dotted
30	 * `catalog.schema.table` (only the parts present). Returns `null` for a
31	 * targetless (not-yet-runnable) suite. Lives here next to the other
32	 * datasource-target-shape logic so a new target field has one owner.
33	 */
34	export function summarizeTarget(target: Record<string, unknown> | null): string | null {
35	  if (!target) return null;
36	  const path = targetString(target, 'path');
37	  if (path) return path;
38	  const parts = [
39	    targetString(target, 'catalog'),
40	    targetString(target, 'schema'),
41	    targetString(target, 'table'),
42	  ].filter((p): p is string => Boolean(p));
43	  return parts.length > 0 ? parts.join('.') : null;
44	}
45	
46	/** The raw target inputs the drawer collects (all optional strings). */
47	export interface TargetFormValues {
48	  target_table?: string;
49	  target_schema?: string;
50	  target_catalog?: string;
51	  target_path?: string;
52	  target_format?: 'csv' | 'parquet';
53	}
54	
55	/** Narrow an untyped stored `file_format` to the supported set, else `undefined`
56	 *  — the suite target is an untyped JSONB bag, so a stray value (e.g. `json`)
57	 *  must not prefill the Select with an option that doesn't exist. */
58	export function asFileFormat(value: string | undefined): 'csv' | 'parquet' | undefined {
59	  return value === 'csv' || value === 'parquet' ? value : undefined;
60	}
61	
62	export interface AssembledTarget {
