import type { CheckCreate } from '../../api/suites';
import { EXPECTATION_BY_TYPE, type ExpectationSpec } from './expectationCatalog';

/**
 * Pure check-authoring form helpers shared by the edit drawer (`CheckDrawer`)
 * and the dedicated create page (`CheckNew`): the form↔payload conversions, so
 * the two surfaces can't drift on kwarg shaping. The matching field components
 * live in `checkFormFields.tsx`.
 */

/** Split a comma-separated list field into trimmed, non-empty items. */
export function parseList(value: unknown): string[] {
  return String(value ?? '')
    .split(',')
    .map((s) => s.trim())
    .filter(Boolean);
}

function numOrNull(v: unknown): number | null {
  return typeof v === 'number' ? v : null;
}

/** Build the GX `config` kwargs from only the selected expectation's fields. */
function formToConfig(
  spec: ExpectationSpec | undefined,
  raw: Record<string, unknown>,
): Record<string, unknown> {
  const config: Record<string, unknown> = {};
  if (!spec) return config;
  for (const field of spec.fields) {
    const value = raw[field.name];
    if (value === undefined || value === null || value === '') continue;
    if (field.type === 'list') {
      const items = parseList(value);
      if (items.length > 0) config[field.name] = items;
    } else {
      config[field.name] = value;
    }
  }
  return config;
}

/** Inverse of formToConfig for edit-mode prefill (list array → comma string). */
export function configToForm(
  spec: ExpectationSpec | undefined,
  config: Record<string, unknown>,
): Record<string, unknown> {
  const form: Record<string, unknown> = {};
  if (!spec) return form;
  for (const field of spec.fields) {
    const value = config[field.name];
    if (value === undefined) continue;
    form[field.name] = field.type === 'list' && Array.isArray(value) ? value.join(', ') : value;
  }
  return form;
}

/** Assemble the create/update payload from validated form values. Rebuilds
 *  `config` from only the selected expectation's fields, so switching types
 *  never leaks stale kwargs. */
export function buildCheckPayload(values: Record<string, unknown>): CheckCreate {
  const spec = EXPECTATION_BY_TYPE[values.expectation_type as string];
  return {
    name: values.name as string,
    expectation_type: values.expectation_type as string,
    config: formToConfig(spec, (values.config ?? {}) as Record<string, unknown>),
    warn_threshold: numOrNull(values.warn_threshold),
    fail_threshold: numOrNull(values.fail_threshold),
    critical_threshold: numOrNull(values.critical_threshold),
  };
}

import { Alert, Button, Descriptions, type FormInstance, Flex, Tag, Typography } from 'antd';
import { useState } from 'react';

import type { ResultStatus } from '../../api/runs';
import { type CheckDryRunResult, dryRunCheck, targetString } from '../../api/suites';
import { RESULT_STATUS_COLORS } from '../results/resultsFormat';
import { ScalarValue } from '../results/ScalarValue';
import { buildCheckPayload } from './checkForm';

/**
 * Inline "preview before saving" affordance for the check editor: runs the
 * in-progress check against the suite's live target via the dry-run API
 * (`POST /suites/{id}/checks/dryrun`) and shows the severity outcome — without
 * persisting a Run/Result. Shared by the create page (`CheckNew`) and the edit
 * drawer (`CheckDrawer`); both pass the suite's run target (#215) so the same
 * `table`/`schema` the run would use is previewed.
 *
 * v1 backend limits (surfaced as the API's error message): dry-run needs a
 * table target and a Snowflake connection. The button is disabled (with a
 * reason) until an expectation is picked and the suite has a table target;
 * everything else (no credential, unreachable warehouse, wrong datasource) comes
 * back as a clean error from the API and renders in the alert.
 */
export function DryRunPreview({
  suiteId,
  expectationType,
  target,
  form,
}: {
  suiteId: string;
  expectationType: string | undefined;
  target: Record<string, unknown> | null;
  form: FormInstance;
}) {
  const [state, setState] = useState<
    | { status: 'idle' }
    | { status: 'running' }
    | { status: 'ok'; result: CheckDryRunResult }
    | { status: 'error'; error: string }
  >({ status: 'idle' });

  // Clear a previous preview when the expectation changes — in the edit drawer
  // the picker switches type in-place (DryRunPreview stays mounted), so without
  // this the old result would linger, misattributed to the new expectation.
