2	import { Alert, App, Button, Card, Flex, Form, Input, Select, Spin, Typography } from 'antd';
3	import { useEffect, useState } from 'react';
4	import { useNavigate, useParams } from 'react-router-dom';
5	
6	import { type ConnectionType, getConnection } from '../api/connections';
7	import { type Check, getCheck, getSuite, updateCheck } from '../api/suites';
8	import { buildCheckPayload, configToForm } from '../components/checks/checkForm';
9	import { ConfigFieldItem, SeverityThresholdFields } from '../components/checks/checkFormFields';
10	import { CheckHistoryDrawer } from '../components/checks/CheckHistoryDrawer';
11	import { ColumnProfilePanel } from '../components/checks/ColumnProfilePanel';
12	import { DryRunPreview } from '../components/checks/DryRunPreview';
13	import {
14	  EXPECTATION_BY_TYPE,
15	  expectationsByCategoryFor,
16	} from '../components/checks/expectationCatalog';
17	import { useAsyncData } from '../hooks/useAsyncData';
18	
19	/**
20	 * Dedicated full-page edit-check flow (ADR 0022 — replaces the edit drawer). The
21	 * expectation Select (grouped by category) drives which config fields render; the
22	 * submitted `config` is rebuilt from only the selected expectation's declared
23	 * fields, so switching types never leaks stale kwargs. Creating a check is the
24	 * dedicated `/suites/:suiteId/checks/new` page. Version history is still a drawer
25	 * (the surviving read-only drawer alongside Share).
26	 */
27	export function CheckEdit() {
28	  const { suiteId, checkId } = useParams<{ suiteId: string; checkId: string }>();
29	  const navigate = useNavigate();
30	  const back = () => navigate(suiteId ? `/suites/${suiteId}` : '/suites');
31	  // Load the suite (target + datasource type) and the check together: the target
32	  // drives the dry-run preview, the connection type gates Custom SQL (ADR 0019),
33	  // and the check seeds the form.
34	  const { state } = useAsyncData(async () => {
35	    if (!suiteId || !checkId) throw new Error('no check');
36	    const [suite, check] = await Promise.all([getSuite(suiteId), getCheck(suiteId, checkId)]);
37	    // Best-effort: a suite may be readable while its connection isn't (shared
38	    // suite). The connection only gates the Custom-SQL category.
39	    const connection = await getConnection(suite.connection_id).catch(() => null);
40	    return { suite, check, connection };
41	  });
42	
43	  return (
44	    <Flex vertical gap={24} style={{ maxWidth: 640 }}>
45	      <Flex justify="space-between" align="center" gap={12}>
46	        <Typography.Title level={3} style={{ margin: 0 }}>
47	          {state.status === 'ok' ? `Edit “${state.data.check.name}”` : 'Edit check'}
48	        </Typography.Title>
49	        <Button onClick={back}>Cancel</Button>
50	      </Flex>
51	
52	      {state.status === 'loading' && <Spin tip="Loading check…" />}
53	      {state.status === 'error' && (
54	        <Alert type="error" showIcon title="Failed to load check" description={state.error} />
55	      )}
56	      {state.status === 'ok' && suiteId && (
57	        <Card size="small">
58	          <CheckEditForm
59	            suiteId={suiteId}
60	            check={state.data.check}
61	            target={state.data.suite.target}
62	            connectionType={state.data.connection?.type}
63	            onCancel={back}
64	            onSaved={back}
65	          />
66	        </Card>
67	      )}
68	    </Flex>
69	  );
70	}
71	
72	function CheckEditForm({
73	  suiteId,
74	  check,
75	  target,
76	  connectionType,
77	  onCancel,
78	  onSaved,
79	}: {
80	  suiteId: string;
81	  check: Check;
82	  target: Record<string, unknown> | null;
83	  connectionType?: ConnectionType;
84	  onCancel: () => void;
85	  onSaved: () => void;
86	}) {
87	  const { message } = App.useApp();
88	  const [form] = Form.useForm();
89	  const [submitting, setSubmitting] = useState(false);
90	  const [historyOpen, setHistoryOpen] = useState(false);
91	  const selectedType = Form.useWatch('expectation_type', form) as string | undefined;
92	  const column = Form.useWatch(['config', 'column'], form) as string | undefined;
93	  const spec = selectedType ? EXPECTATION_BY_TYPE[selectedType] : undefined;
94	
95	  // Seed from the loaded check once.
96	  useEffect(() => {
97	    form.setFieldsValue({
98	      name: check.name,
99	      expectation_type: check.expectation_type,
100	      config: configToForm(EXPECTATION_BY_TYPE[check.expectation_type], check.config),
101	      warn_threshold: check.warn_threshold ?? undefined,
102	      fail_threshold: check.fail_threshold ?? undefined,
103	      critical_threshold: check.critical_threshold ?? undefined,
104	    });
105	  }, [check, form]);
106	
107	  const onSubmit = async () => {
108	    let values: Record<string, unknown>;
109	    try {
110	      values = await form.validateFields();
111	    } catch {
112	      return; // inline validation errors
113	    }
114	    setSubmitting(true);
115	    try {
116	      await updateCheck(suiteId, check.id, buildCheckPayload(values));
117	      message.success(`${values.name as string}: saved`);
118	      onSaved();
119	    } catch (err) {
120	      message.error(`Save failed: ${err instanceof Error ? err.message : 'unknown error'}`);
121	    } finally {
122	      setSubmitting(false);
123	    }
124	  };
125	
126	  return (
127	    <>
128	      <Form form={form} layout="vertical" onFinish={onSubmit}>
129	        <Form.Item name="name" label="Name" rules={[{ required: true }]}>
130	          <Input placeholder="e.g. order_id not null" />
131	        </Form.Item>
132	        <Form.Item name="expectation_type" label="Expectation" rules={[{ required: true }]}>
133	          <Select
134	            placeholder="Select an expectation"
135	            // Grouped by category (antd optgroups). Pass the check's current type
136	            // so Custom SQL stays selectable even before the connection loads.
137	            options={expectationsByCategoryFor(connectionType, check.expectation_type).map((g) => ({
138	              label: g.category,
139	              options: g.specs.map((e) => ({ value: e.type, label: e.label })),
140	            }))}
141	          />
142	        </Form.Item>
143	
144	        {spec && (
145	          <>
146	            <Typography.Paragraph type="secondary" style={{ marginTop: -8 }}>
147	              {spec.description}
148	            </Typography.Paragraph>
149	            {spec.fields.map((field) => (
150	              <ConfigFieldItem key={field.name} field={field} />
151	            ))}
152	          </>
153	        )}
154	
155	        <SeverityThresholdFields />
156	
157	        <Form.Item>
158	          <ColumnProfilePanel suiteId={suiteId} target={target} column={column} />
159	        </Form.Item>
160	        <Form.Item>
161	          <DryRunPreview
162	            suiteId={suiteId}
163	            expectationType={selectedType}
164	            target={target}
165	            form={form}
166	          />
167	        </Form.Item>
168	
169	        <Flex justify="space-between" align="center" gap={8}>
170	          <Button icon={<HistoryOutlined />} onClick={() => setHistoryOpen(true)}>
171	            History
172	          </Button>
173	          <Flex gap={8}>
174	            <Button onClick={onCancel}>Cancel</Button>
175	            <Button type="primary" htmlType="submit" loading={submitting}>
176	              Save
177	            </Button>
178	          </Flex>
179	        </Flex>
180	      </Form>
181	
182	      <CheckHistoryDrawer
183	        open={historyOpen}
184	        suiteId={suiteId}
185	        check={check}
186	        onClose={() => setHistoryOpen(false)}
187	      />
188	    </>
189	  );
190	}

